[BusinessEvents(classStr(PurchGRNBusinessEventContract), "PurchGRNCreated", "Fires when a Purchase Order Product Receipt (GRN) is posted", ModuleAxapta::PurchaseOrder)]
public final class PurchGRNBusinessEvent extends BusinessEventsBase
{
    private VendPackingSlipJour packingSlipJour;

}

Method.Source:
private VendPackingSlipJour parmPackingSlipJour(VendPackingSlipJour _packingSlipJour = packingSlipJour)
{
    packingSlipJour = _packingSlipJour;
    return packingSlipJour;
}

public static PurchGRNBusinessEvent newFromVendPackingSlipJour(VendPackingSlipJour _packingSlipJour)
{
    PurchGRNBusinessEvent businessEvent = new PurchGRNBusinessEvent();
    businessEvent.parmPackingSlipJour(_packingSlipJour);
    return businessEvent;
}
